  match_no = excluded.match_no,
  phase = excluded.phase,
  kickoff_at = excluded.kickoff_at,
  venue = excluded.venue,
  home_team = excluded.home_team,
  away_team = excluded.away_team,
  source = excluded.source,
  source_updated_at = excluded.source_updated_at,
  status = case when public.matches.status = 'finished' then public.matches.status else excluded.status end,
  home_score = case when public.matches.status = 'finished' then public.matches.home_score else public.matches.home_score end,
  away_score = case when public.matches.status = 'finished' then public.matches.away_score else public.matches.away_score end,
